  function applyPure(name: string, title: string, description: string): FileMap | null {
    const tpl = PURE_TEMPLATES[name];
    if (!tpl) return null;
    const out: FileMap = {};
    for (const [fname, content] of Object.entries(tpl)) {
      out[fname] = content.split(TITLE_PH).join(title).split(DESC_PH).join(description);
    }
    return out;
  }

  // ─── Default category-aware Python pentest scaffold ───────────────────────────
  const LICENSE = "MIT License\n\nCopyright (c) 2026 Archibald Titan Marketplace\n\nPermission is hereby granted, free of charge, to any person obtaining a copy of this software, to deal in the Software without restriction. Use only on systems you are authorized to test.\nTHE SOFTWARE IS PROVIDED \"AS IS\", WITHOUT WARRANTY OF ANY KIND.\n";
  const GITIGNORE = "__pycache__/\n*.pyc\n.venv/\nvenv/\n.env\n*.log\noutput/\nreports/\n";

  function defaultMode(title: string, description: string): string {
    const t = (title + " " + description).toLowerCase();
    if (/aws|s3|iam|cloudtrail|gcp|azure|ec2|lambda/.test(t)) return "cloud";
    if (/k8s|kubernetes|docker|container|helm|istio|service mesh/.test(t)) return "container";
    if (/sast|code scan|sca|dependency|sbom|license/.test(t)) return "appsec";
    if (/malware|reverse|yara|pe |elf |apk|firmware/.test(t)) return "reverse";
    if (/forensic|incident|memory|event log|artifact|timeline/.test(t)) return "forensics";
    if (/llm|prompt|jailbreak|model|adversarial|chatgpt|ai/.test(t)) return "aisec";
    if (/smart contract|solidity|defi|nft|blockchain|ethereum/.test(t)) return "web3";
    if (/jwt|oauth|saml|webauthn|sso|mfa/.test(t)) return "auth";
    if (/threat intel|misp|ioc|otx|stix|taxii|dark web/.test(t)) return "intel";
    if (/siem|log|splunk|elk|sigma|detection rule/.test(t)) return "detect";
    if (/persistence|lateral|kerberos|ldap|active directory|bloodhound/.test(t)) return "offense";
    if (/modbus|scada|ics|plc|industrial/.test(t)) return "ics";
    if (/tpm|attestation|secure boot|fido|hsm/.test(t)) return "crypto";
    return "web";
  }

  function buildDefaultPentest(title: string, description: string): FileMap {
    const mode = defaultMode(title, description);
    const safeName = title.replace(/[^\w\-]/g, "").slice(0, 40).toLowerCase() || "tool";
    const safeDesc = description.replace(/'/g, "\\'").slice(0, 120);

    const readme = `# ${title}

  ${description}

  Mode: \`${mode}\` — module loadout adapts to the tool's domain.

  ## Install
  \`\`\`bash
  pip install -r requirements.txt
  cp config.example.yaml config.yaml
  \`\`\`

  ## Usage
  \`\`\`bash
  python3 cli.py scan --target <target> --output report.json
  python3 cli.py report --input report.json --format html --output report.html
  python3 cli.py --help
  \`\`\`

  See \`docs/architecture.md\` for module details.
  `;

    const cli = `#!/usr/bin/env python3
  """${title} - CLI entry point."""
  import argparse, json, sys, asyncio
  from pathlib import Path
  from core.scanner import Scanner
  from core.reporter import Reporter
  from core.config import load_config

  MODE = "${mode}"

  def cmd_scan(args):
      cfg = load_config(args.config)
      cfg['target'] = args.target
      cfg['mode'] = MODE
      scanner = Scanner(cfg)
      results = asyncio.run(scanner.run())
      Path(args.output).write_text(json.dumps(results, indent=2, default=str))
      print(f'[*] {len(results.get("findings", []))} findings -> {args.output}', file=sys.stderr)

  def cmd_report(args):
      data = json.loads(Path(args.input).read_text())
      rep = Reporter(data)
      out = rep.render(args.format)
      Path(args.output).write_text(out)
      print(f'[*] Report ({args.format}) -> {args.output}', file=sys.stderr)

  def main():
      p = argparse.ArgumentParser(prog='${safeName}', description='${safeDesc}')
      sub = p.add_subparsers(dest='cmd', required=True)
      s = sub.add_parser('scan'); s.add_argument('--target', required=True); s.add_argument('--config', default='config.yaml'); s.add_argument('--output', default='report.json'); s.set_defaults(fn=cmd_scan)
      r = sub.add_parser('report'); r.add_argument('--input', required=True); r.add_argument('--format', choices=['json','html','csv'], default='html'); r.add_argument('--output', default='report.html'); r.set_defaults(fn=cmd_report)
      a = p.parse_args(); a.fn(a)

  if __name__ == '__main__': main()
  `;

    // Build remaining files (these don't change per mode)
    const files: FileMap = {
      "README.md": readme,
      "cli.py": cli,
      "core/__init__.py": "",
      "core/config.py": "import yaml\n  from pathlib import Path\n\n  DEFAULTS = {\n      'concurrency': 20,\n      'timeout': 10,\n      'user_agent': 'archibald-titan-scanner/1.0',\n      'output_dir': './output',\n      'rules_dir': './rules',\n  }\n\n  def load_config(path):\n      cfg = dict(DEFAULTS)\n      p = Path(path)\n      if p.exists():\n          cfg.update(yaml.safe_load(p.read_text()) or {})\n      return cfg\n  ",
      "core/scanner.py": "\"\"\"Scanner core - dispatches probes based on mode.\"\"\"\n  import asyncio, importlib\n\n  MODE_PROBES = {\n      'web': ['probes.http_headers', 'probes.tls_audit', 'probes.cors_check', 'probes.cookies'],\n      'cloud': ['probes.cloud_metadata', 'probes.public_resources'],\n      'container': ['probes.container_runtime', 'probes.image_metadata'],\n      'appsec': ['probes.dependency_audit', 'probes.license_audit'],\n      'reverse': ['probes.binary_metadata', 'probes.entropy'],\n      'forensics': ['probes.timeline', 'probes.artifact_extract'],\n      'aisec': ['probes.llm_health', 'probes.canary_check'],\n      'web3': ['probes.contract_metadata'],\n      'auth': ['probes.token_decode', 'probes.flow_check'],\n      'intel': ['probes.ioc_enrich'],\n      'detect': ['probes.log_parse', 'probes.rule_eval'],\n      'offense': ['probes.target_recon'],\n      'ics': ['probes.protocol_probe'],\n      'crypto': ['probes.cert_chain', 'probes.alg_audit'],\n  }\n\n  class Scanner:\n      def __init__(self, cfg): self.cfg = cfg\n      async def run(self):\n          mode = self.cfg.get('mode', 'web')\n          modules = MODE_PROBES.get(mode, MODE_PROBES['web'])\n          findings = []\n          for m in modules:\n              try:\n                  mod = importlib.import_module(m)\n                  fs = await mod.probe(self.cfg)\n                  findings.extend(fs)\n              except ModuleNotFoundError:\n                  findings.append({'probe': m, 'severity': 'INFO', 'message': f'probe module {m} not implemented in this build'})\n              except Exception as e:\n                  findings.append({'probe': m, 'severity': 'ERROR', 'message': str(e)})\n          return {'target': self.cfg.get('target'), 'mode': mode, 'findings': findings, 'summary': {\n              'total': len(findings),\n              'critical': sum(1 for f in findings if f.get('severity') == 'CRITICAL'),\n              'high': sum(1 for f in findings if f.get('severity') == 'HIGH'),\n              'medium': sum(1 for f in findings if f.get('severity') == 'MEDIUM'),\n          }}\n  ",
      "core/reporter.py": "\"\"\"Render findings as JSON/HTML/CSV.\"\"\"\nimport json, html, csv, io\n\nclass Reporter:\n    def __init__(self, data): self.data = data\n    def render(self, fmt):\n        if fmt == 'json': return json.dumps(self.data, indent=2, default=str)\n        if fmt == 'csv':\n            buf = io.StringIO(); w = csv.DictWriter(buf, fieldnames=['probe','severity','message'])\n            w.writeheader()\n            for f in self.data.get('findings', []): w.writerow({'probe': f.get('probe',''), 'severity': f.get('severity',''), 'message': f.get('message','')})\n            return buf.getvalue()\n        return self._html()\n    def _html(self):\n        rows = ''.join(f'<tr class=\"sev-{html.escape(str(f.get(\"severity\",\"\")))}\"><td>{html.escape(str(f.get(\"probe\",\"\")))}</td><td>{html.escape(str(f.get(\"severity\",\"\")))}</td><td>{html.escape(str(f.get(\"message\",\"\")))}</td></tr>' for f in self.data.get('findings', []))\n        s = self.data.get('summary', {})\n        return f'''<!doctype html><html><head><meta charset=\"utf-8\"><title>Scan Report</title><style>body{{font-family:system-ui;margin:2em;background:#0a0a0f;color:#e8e8ee}}h1{{color:#7df}}table{{border-collapse:collapse;width:100%}}td,th{{padding:.5em .8em;border-bottom:1px solid #333;text-align:left}}.sev-CRITICAL{{background:#3b0d0d}}.sev-HIGH{{background:#3a200d}}.sev-MEDIUM{{background:#332a0d}}.sev-INFO{{background:#0d2333}}.summary{{display:flex;gap:1em;margin:1em 0}}.summary div{{padding:.6em 1em;border-radius:6px;background:#181822;border:1px solid #333}}</style></head><body><h1>${title}</h1><p>Target: <code>{html.escape(str(self.data.get(\"target\",\"\")))}</code> · Mode: <code>{html.escape(str(self.data.get(\"mode\",\"\")))}</code></p><div class=\"summary\"><div>Total: {s.get(\"total\",0)}</div><div style=\"color:#ff6b6b\">Critical: {s.get(\"critical\",0)}</div><div style=\"color:#ffa94d\">High: {s.get(\"high\",0)}</div><div style=\"color:#ffd43b\">Medium: {s.get(\"medium\",0)}</div></div><table><thead><tr><th>Probe</th><th>Severity</th><th>Message</th></tr></thead><tbody>{rows}</tbody></table></body></html>'''\n",
      "probes/__init__.py": "",
      "probes/http_headers.py": "\"\"\"Probe: HTTP security headers audit.\"\"\"\nimport aiohttp\n\nREQUIRED = {\n    'Strict-Transport-Security': 'HIGH',\n    'Content-Security-Policy': 'HIGH',\n    'X-Frame-Options': 'MEDIUM',\n    'X-Content-Type-Options': 'MEDIUM',\n    'Referrer-Policy': 'MEDIUM',\n    'Permissions-Policy': 'INFO',\n}\n\nasync def probe(cfg):\n    target = cfg.get('target')\n    if not target: return []\n    findings = []\n    try:\n        async with aiohttp.ClientSession() as s:\n            async with s.get(target, ssl=False, timeout=aiohttp.ClientTimeout(total=cfg.get('timeout', 10))) as r:\n                for h, sev in REQUIRED.items():\n                    if h not in r.headers: findings.append({'probe': 'http_headers', 'severity': sev, 'message': f'Missing security header: {h}'})\n                srv = r.headers.get('server','')\n                if srv: findings.append({'probe': 'http_headers', 'severity': 'INFO', 'message': f'Server banner disclosed: {srv}'})\n    except Exception as e:\n        findings.append({'probe': 'http_headers', 'severity': 'ERROR', 'message': f'fetch failed: {e}'})\n    return findings\n",
      "probes/tls_audit.py": "\"\"\"Probe: TLS configuration audit (cert + protocol).\"\"\"\nimport ssl, socket\nfrom urllib.parse import urlparse\n\nasync def probe(cfg):\n    u = urlparse(cfg.get('target', ''))\n    host, port = u.hostname, u.port or (443 if u.scheme == 'https' else 80)\n    if not host or u.scheme != 'https': return []\n    findings = []\n    try:\n        ctx = ssl.create_default_context()\n        with socket.create_connection((host, port), timeout=cfg.get('timeout', 10)) as sock:\n            with ctx.wrap_socket(sock, server_hostname=host) as ssock:\n                cert = ssock.getpeercert()\n                proto = ssock.version()\n                if proto in ('TLSv1', 'TLSv1.1'): findings.append({'probe':'tls_audit','severity':'HIGH','message':f'Weak TLS version: {proto}'})\n                if proto == 'TLSv1.3': findings.append({'probe':'tls_audit','severity':'INFO','message':f'TLS 1.3 enabled'})\n                cipher = ssock.cipher()\n                if cipher and 'RC4' in cipher[0]: findings.append({'probe':'tls_audit','severity':'CRITICAL','message':f'RC4 cipher in use: {cipher[0]}'})\n                findings.append({'probe':'tls_audit','severity':'INFO','message':f'Cipher: {cipher[0] if cipher else \"unknown\"}'})\n                findings.append({'probe':'tls_audit','severity':'INFO','message':f'Cert subject: {cert.get(\"subject\", \"?\")}'})\n    except Exception as e: findings.append({'probe':'tls_audit','severity':'ERROR','message':str(e)})\n    return findings\n",
      "probes/cors_check.py": "\"\"\"Probe: CORS misconfig - reflects arbitrary Origin?\"\"\"\nimport aiohttp\n\nasync def probe(cfg):\n    target = cfg.get('target');\n    if not target: return []\n    findings = []\n    try:\n        async with aiohttp.ClientSession() as s:\n            async with s.get(target, headers={'Origin': 'https://evil.example.com'}, ssl=False, timeout=aiohttp.ClientTimeout(total=cfg.get('timeout',10))) as r:\n                aco = r.headers.get('Access-Control-Allow-Origin', '')\n                acc = r.headers.get('Access-Control-Allow-Credentials', '')\n                if aco == 'https://evil.example.com':\n                    sev = 'CRITICAL' if acc.lower() == 'true' else 'HIGH'\n                    findings.append({'probe':'cors_check','severity':sev,'message':f'CORS reflects arbitrary Origin (credentials={acc})'})\n                elif aco == '*' and acc.lower() == 'true':\n                    findings.append({'probe':'cors_check','severity':'CRITICAL','message':'ACAO=* with credentials=true (browser blocks but indicates misconfig)'})\n    except Exception as e: findings.append({'probe':'cors_check','severity':'ERROR','message':str(e)})\n    return findings\n",
      "probes/cookies.py": "\"\"\"Probe: cookie security flags.\"\"\"\nimport aiohttp\n\nasync def probe(cfg):\n    target = cfg.get('target');\n    if not target: return []\n    findings = []\n    try:\n        async with aiohttp.ClientSession() as s:\n            async with s.get(target, ssl=False, timeout=aiohttp.ClientTimeout(total=cfg.get('timeout',10))) as r:\n                for raw in r.headers.getall('Set-Cookie', []):\n                    name = raw.split('=', 1)[0]\n                    flags = raw.lower()\n                    if 'secure' not in flags: findings.append({'probe':'cookies','severity':'HIGH','message':f'Cookie {name} missing Secure flag'})\n                    if 'httponly' not in flags: findings.append({'probe':'cookies','severity':'HIGH','message':f'Cookie {name} missing HttpOnly flag'})\n                    if 'samesite' not in flags: findings.append({'probe':'cookies','severity':'MEDIUM','message':f'Cookie {name} missing SameSite attribute'})\n    except Exception as e: findings.append({'probe':'cookies','severity':'ERROR','message':str(e)})\n    return findings\n",
      "config.example.yaml": "concurrency: 20\ntimeout: 10\nuser_agent: archibald-titan-scanner/1.0\noutput_dir: ./output\nrules_dir: ./rules\n",
      "requirements.txt": "aiohttp>=3.9\nPyYAML>=6.0\n",
      "tests/test_smoke.py": "\"\"\"Smoke test - ensures CLI loads and reporter renders.\"\"\"\nimport subprocess, json, sys\n\ndef test_cli_help():\n    r = subprocess.run([sys.executable, 'cli.py', '--help'], capture_output=True, text=True)\n    assert r.returncode == 0\n    assert 'scan' in r.stdout\n\ndef test_reporter_html():\n    from core.reporter import Reporter\n    r = Reporter({'target':'http://x','mode':'web','findings':[{'probe':'p','severity':'HIGH','message':'m'}],'summary':{'total':1,'high':1}})\n    h = r.render('html')\n    assert '<table>' in h and 'HIGH' in h\n",
      "docs/architecture.md": "# Architecture\n\n```\ncli.py            # entry point\n├── scan         # runs configured probes\n└── report       # renders results\n\ncore/\n├── config.py    # YAML config loader with defaults\n├── scanner.py   # dispatches probes by mode\n└── reporter.py  # JSON/HTML/CSV rendering\n\nprobes/\n├── http_headers.py\n├── tls_audit.py\n├── cors_check.py\n└── cookies.py\n```\n\n## Adding a probe\n1. Drop a new module in `probes/` exporting `async def probe(cfg) -> list[dict]`.\n2. Add it to `MODE_PROBES` in `core/scanner.py`.\n3. Each finding dict needs `probe`, `severity` (`CRITICAL|HIGH|MEDIUM|INFO|ERROR`), `message`.\n\n## Mode for this build\n`web` — see `core/scanner.py` for the loaded probe list. Some probes may be no-ops in this distribution; extend `probes/` to add domain-specific checks.\n",
      "LICENSE": LICENSE,
      ".gitignore": GITIGNORE,
    };
    // reporter has ${title} placeholder we need to swap
    files["core/reporter.py"] = files["core/reporter.py"].replace(/\${title}/g, title);
    files["docs/architecture.md"] = files["docs/architecture.md"].replace(/\${mode}/g, mode);
    return files;
  }

  // ─── Router ───────────────────────────────────────────────────────────────────
  export function pickCyberTemplate(title: string, description: string, language: string = "python"): FileMap {
    const t = (title + " " + description).toLowerCase();
    // Specialized routes (most-specific first)
    if (/prompt injection|jailbreak|llm fuzz/.test(t)) return applyPure("prompt_injection", title, description)!;
    if (/secret scan|credential scan|leak detect|gitleaks|trufflehog/.test(t)) return applyPure("secret_scanner", title, description)!;
    if (/s3 (bucket|audit|misconfig)|aws s3/.test(t)) return applyPure("s3_audit", title, description)!;
    if (/jwt|json web token/.test(t)) return applyPure("jwt_auditor", title, description)!;
    if (/subdomain|dns recon|asset discovery/.test(t)) return applyPure("subdomain_recon", title, description)!;
    if (/(http|web|content) (fuzz|brute|discovery)|directory brute|content discovery|gobuster|ffuf/.test(t)) return applyPure("http_fuzzer", title, description)!;
    // Default: category-aware pentest scaffold
    return buildDefaultPentest(title, description);
  }
  